# OEIS sequence: A096002

from sympy import isprime, primefactors
def A096002(n):
    if isprime(n) or n == 1: return n-1
    q, c = 1, -2
    for p in sorted(primefactors(n)):
        c += p//q
        q *= p
    return int(c+n//q) # _Chai Wah Wu_, Jun 13 2026

